<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Timesheets</h1><p class="text-muted mb-0">Job, travel, shop, training, and administrative time.</p></div><?php if(\App\Core\Auth::can('owner','office')):?><a class="btn btn-outline-primary" href="/portal/timesheets/export?from=<?=e($from)?>&to=<?=e($to)?>"><i class="fa-solid fa-file-csv me-2"></i>Payroll Export</a><?php endif?></div>
<div class="row g-4"><div class="col-lg-4"><div class="card card-body"><h2 class="h5">Clock</h2><form method="post" action="/portal/timesheets/clock"><?=csrf_field()?><div class="mb-3"><label class="form-label">Type</label><select class="form-select" name="entry_type"><option>job</option><option>travel</option><option>shop</option><option>training</option><option>administrative</option></select></div><div class="mb-3"><label class="form-label">Job</label><select class="form-select" name="job_id"><option value="">None</option><?php foreach($jobs as $j):?><option value="<?=$j['id']?>"><?=e($j['job_number'])?></option><?php endforeach?></select></div><div class="mb-3"><label class="form-label">Vehicle</label><select class="form-select" name="vehicle_id"><option value="">None</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>"><?=e($v['unit_number'])?></option><?php endforeach?></select></div><div class="mb-3"><label class="form-label">Notes</label><input class="form-control" name="notes"></div><button class="btn btn-primary w-100">Clock In / Out</button></form></div></div><div class="col-lg-8"><form class="d-flex gap-2 mb-3"><input type="date" class="form-control" name="from" value="<?=e($from)?>"><input type="date" class="form-control" name="to" value="<?=e($to)?>"><button class="btn btn-outline-primary">Apply</button></form><div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Employee</th><th>Type</th><th>Clock in</th><th>Clock out</th><th>Hours</th><th>Job</th><th>Approved</th></tr></thead><tbody><?php foreach($entries as $e):?><tr><td><?=e($e['name'])?></td><td><?=e($e['entry_type'])?></td><td><?=e($e['clock_in'])?></td><td><?=e($e['clock_out']?:'Open')?></td><td><?=number_format(max(0,(float)$e['minutes'])/60,2)?></td><td><?=e($e['job_number'])?></td><td><?php if($e['approved_at']):?><i class="fa-solid fa-check text-success"></i><?php elseif(\App\Core\Auth::can('owner','office','crew_leader')):?><form method="post" action="/portal/timesheets/<?=$e['id']?>/approve"><?=csrf_field()?><button class="btn btn-sm btn-outline-success">Approve</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
